import UIKit
import Alamofire

class TradeViewController: UIViewController {
    
    var stocks = [Stock]()
    var selectedStock: Stock?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        fetchStockData()
    }
    
    func fetchStockData() {
        let url = "https://api.example.com/stocks"
        
        AF.request(url, method: .get).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let json = value as? [String: Any], let stockArray = json["stocks"] as? [[String: Any]] {
                    self.stocks = stockArray.compactMap { Stock(json: $0) }
                    DispatchQueue.main.async {
                        // Update UI with fetched stocks
                    }
                }
            case .failure(let error):
                print("Error fetching stock data: \(error)")
            }
        }
    }
    
    func executeTrade(stock: Stock, quantity: Int, isBuy: Bool) {
        guard let selectedStock = selectedStock else { return }
        
        let url = "https://api.example.com/trade"
        let parameters: [String: Any] = [
            "stockId": selectedStock.id,
            "quantity": quantity,
            "isBuy": isBuy
        ]
        
        AF.request(url, method: .post, parameters: parameters).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let json = value as? [String: Any], let success = json["success"] as? Bool, success {
                    DispatchQueue.main.async {
                        // Update UI after successful trade execution
                    }
                } else {
                    print("Trade failed")
                }
            case .failure(let error):
                print("Error executing trade: \(error)")
            }
        }
    }
}

struct Stock {
    let id: Int
    let name: String
    let price: Double
    
    init?(json: [String: Any]) {
        guard let id = json["id"] as? Int,
              let name = json["name"] as? String,
              let price = json["price"] as? Double else { return nil }
        
        self.id = id
        self.name = name
        self.price = price
    }
}